// Seeded PRNG + helpers — shared by every game so an online match can replay an
// identical rack/break from one seed (ported from pool.html's mkRng / mulberry32).

/** mulberry32 — returns a deterministic () => float in [0,1) from an integer seed. */
export function seeded(seed) {
  let s = seed | 0;
  return () => {
    s = (s + 0x6D2B79F5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** Fisher–Yates using a supplied rng (defaults to Math.random). Returns a new array. */
export function shuffle(arr, rng = Math.random) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
